(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["chunks/Desktop_elektronova-recovered_f290b455._.js",45914,(e,t,i)=>{self._ENTRIES||={};let o=Promise.resolve().then(()=>e.i(34112));o.catch(()=>{}),self._ENTRIES.middleware_middleware=new Proxy(o,{get(e,t){if("then"===t)return(t,i)=>e.then(t,i);let i=(...i)=>e.then(e=>(0,e[t])(...i));return i.then=(i,o)=>e.then(e=>e[t]).then(i,o),i}})},20715,e=>{e.v(JSON.parse('{"Index":{"title":"ElektroNova - Fuqizojmë Sigurinë Tuaj","description":"Zgjidhje premium për sigurinë dhe instalimet elektrike në tërë Kosovën.","hero_badge":"ElektroNova - Fuqizojmë Sigurinë Tuaj","hero_h1":"Fuqizojmë <gradient>Sigurinë</gradient> Tuaj me Teknologji","hero_p":"ElektroNova ofron zgjidhje premium për monitorim, alarm dhe instalime elektrike. Siguria juaj është prioriteti ynë kryesor në mbarë Kosovën.","services_title":"Shërbimet tona <highlight>Kryesore</highlight>","services_highlight":"Kryesore","services_p":"Ne ofrojmë një gamë të gjerë shërbimesh teknologjike për të siguruar mjedisin tuaj.","view_all_services":"Shih të gjitha shërbimet","testimonials_title":"Besimi i <highlight>Klientëve</highlight>","testimonials_p":"Çfarë thonë ata që kanë besuar sigurinë e tyre në duart tona.","mission_badge":"Misioni & Historia Jonë","mission_title":"Mbi Një Dekadë Përvojë në <highlight>Teknologjinë e Sigurisë</highlight>","mission_p1":"ElektroNova nuk është thjesht një emër në industrinë e sigurisë; është një premtim për mbrojtje dhe profesionalizëm. E themeluar në Pejë, kompania jonë lindi nga nevoja për të sjellë standarde evropiane në fushën e video-vëzhgimit dhe instalimeve elektrike në tërë Kosovën.","mission_p2":"Gjatë viteve, ne kemi evoluar së bashku me teknologjinë. Nga kamerat analoge të para 10 viteve, sot jemi lider në instalimin e sistemeve me Inteligjencë Artificiale, njohje të fytyrave dhe sistemeve smart home që menaxhohen plotësisht nga celulari.","mission_p3":"Sot, ne mbulojmë çdo qytet të Kosovës, duke ofruar shërbime të shpejta dhe mirëmbajtje 24/7. Ne besojmë se teknologjia duhet t\'i shërbejë njerëzve, andaj çdo projekt i yni projektohet në mënyrë specifike për të plotësuar nevojat unike të klientëve tanë.","recent_work_title":"Punët tona të <highlight>Fundit</highlight>","recent_work_p":"Pamje direkte nga instalimet tona reale në tërë Kosovën.","view_full_gallery":"Shih Galerinë e Plotë","why_title":"Pse të zgjidhni <highlight>ElektroNova</highlight>?","why_1_title":"Instalim Profesional & Kabllim i Fshehur","why_1_p":"Teknikët tanë të trajnuar sigurojnë që çdo instalim të kryhet sipas standardeve më të larta të sigurisë, duke fshehur dhe mbrojtur çdo kabull.","why_2_title":"Mbështetje Lokale 24/7 në tërë Kosovën","why_2_p":"Me seli në Pejë, ne mbulojmë të gjitha qytetet e Kosovës me ndërhyrje të shpejtë, mirëmbajtje dhe asistencë teknike.","why_3_title":"Teknologjia e Fundit e Brendeve Botërore","why_3_p":"Punojmë vetëm me brendet lider botërorë si Dahua, Hikvision dhe Ajax për të garantuar jetëgjatësi.","consultation_title":"Kërkoni një Konsultë <highlight>Falas</highlight>","faq_title":"Pyetjet e <highlight>Shpeshta</highlight>","faq_p":"Çfarë dëshirojnë të dinë klientët tanë para se të instalojnë sistemet e sigurisë.","faq_1_q":"A mund t\'i shoh kamerat nga telefoni kudo që jam?","faq_1_a":"Po, plotësisht. Sistemet tona lidhen me internetin dhe ju lejojnë të shihni pamjet në kohë reale falas përmes aplikacioneve zyrtare Android dhe iOS.","faq_2_q":"Sa kohë zgjat një instalim i plotë?","faq_2_a":"Për një shtëpi mesatare me 4 deri 8 kamera, instalimi zakonisht përfundohet brenda një dite pune, duke përfshirë kabllimin dhe konfigurimin e aplikacionit.","faq_3_q":"Çfarë ndodh nëse bie rryma apo interneti?","faq_3_a":"Sistemet tona mund të pajisen me bateri rezervë (UPS) që mbajnë kamerat ndezur. Nëse bie interneti, regjistrimi vazhdon në Hard Disk lokalisht.","faq_4_q":"A ofroni garanci për pajisjet dhe punën?","faq_4_a":"Po, ElektroNova ofron garanci të plotë për të gjitha pajisjet e brendeve zyrtare (1-2 vite) si dhe garanci për korrektësinë e instalimit teknik.","faq_5_q":"A është sistemi i alarmit i vështirë për t\'u përdorur?","faq_5_a":"Jo, sistemet tona moderne bëhen me kod ose pult, dhe njoftimet vijnë në celular në gjuhën shqipe, duke e bërë shumë të thjeshtë për secilin.","faq_6_q":"A mbuloni të gjithë territorin e Kosovës?","faq_6_a":"Po, ekipi ynë mobil vjen në çdo qytet dhe fshat të Kosovës për llogaritje të ofertës, instalim dhe mirëmbajtje të sistemeve.","brands_p":"Punojmë me brendet më të mira botërore"},"Navigation":{"home":"Ballina","about":"Rreth Nesh","services":"Shërbimet","portfolio":"Portofolio","brands":"Brendet","blog":"Blogu","faq":"FAQ","contact":"Kontakti","footer_desc":"Zgjidhje premium për sigurinë dhe instalimet elektrike. Fuqizojmë sigurinë tuaj me teknologjinë më të fundit.","quick_links":"Lidhje të Shpejta","contact_us":"Na Kontaktoni","working_hours":"Orari i Punës","mon_fri":"E hënë - E premte","sat_sun":"E shtunë - E diel","closed":"Mbyllur","rights":"Të gjitha të drejtat e rezervuara.","privacy_policy":"Politika e Privatësisë","terms_of_service":"Kushtet e Përdorimit","locations":"Lokacionet"},"Common":{"whatsapp":"Na kontaktoni në WhatsApp","call":"Thirrni tani","quote":"Kërkoni ofertë","send":"Dërgo","name":"Emri Mbiemri","email":"Email Adresa","phone":"Numri i Telefonit","message":"Mesazhi juaj","sending":"Duke u dërguar...","success_title":"Ju faleminderit!","success_message":"Mesazhi juaj u dërgua me sukses. Ekipi ynë do t\'ju kontaktojë së shpejti.","error_message":"Diçka shkoi keq. Ju lutem provoni përsëri ose na kontaktoni në WhatsApp.","send_another":"Dërgoni një mesazh tjetër"},"Blog":{"title":"Blogu i <highlight>ElektroNova</highlight>","subtitle":"Këshilla profesionale, krahasime produktesh dhe lajmet e fundit nga bota e sigurisë teknologjike.","meta_description":"Lexoni artikujt tanë të fundit rreth sigurisë, teknologjisë CCTV dhe instalimeve elektrike falas.","back_to_blog":"Kthehu te të gjithë artikujt","security_expert":"Ekspert i Sigurisë","questions_title":"Keni pyetje rreth kësaj teme?","share":"Shpërndaje","related_services":"Shërbime të Ndërlidhura"},"Services":{"title_main":"Shërbimet tona","title_highlight":"Profesionale","title_suffix":"","description":"ElektroNova ofron zgjidhje të kompletuara për sigurinë dhe nevojat elektrike. Nga projektimi deri te instalimi dhe mirëmbajtja.","cat_cctv":"Sisteme të Monitorimit (CCTV)","cat_security":"Alarme dhe Siguri","cat_electrical":"Instalime Elektrike & Rrjeta","service_description":"Zgjidhje profesionale e përshtatur për nevojat tuaja specifike, duke garantuar cilësi dhe siguri maksimale.","cta_title":"Nuk jeni të sigurt çfarë ju duhet?","cta_desc":"Na kontaktoni sot për një konsultë falas dhe vlerësim të mjedisit tuaj nga ekspertët tanë.","call_expert":"Thirrni Ekspertin","whatsapp":"WhatsApp","related_articles":"Artikuj të Ndërlidhur","back_to_services":"Kthehu te të gjitha shërbimet","service_description_title":"Përshkrimi i Shërbimit","main_benefits":"Përfitimet Kryesore","tech_used":"Teknologjia e Përdorur","where_applies":"Ku mund të aplikohet?","install_process":"Procesi i Instalimit","service_faq":"Pyetjet rreth Shërbimit","get_quote":"Merrni një Ofertë","quote_desc":"Interesoheni për këtë shërbim? Plotësoni formën më poshtë dhe ekipi ynë do t\'ju kontaktojë brenda 24 orëve.","need_help":"Nevojë për Ndihmë?","free_cons_desc":"Na thirrni në çdo kohë për konsultim falas."},"Portfolio":{"title_main":"Portofolio i","title_highlight":"Realizimeve","description":"Pamje nga instalimet tona reale në terren. Çdo foto tregon përkushtimin tonë ndaj cilësisë dhe profesionalizmit.","cta_title":"Gati për të siguruar pronën tuaj?","cta_desc":"Ne vijmë kudo në Kosovë për vlerësimin e projektit tuaj pa asnjë pagesë.","request_quote":"Kërko Ofertën","call_phone":"Thirr në Telefon"},"About":{"title_main":"Rreth","title_highlight":"ElektroNova","vision_title":"Vizioni ynë","vision_p":"Themeluar më 08 Janar 2025 në qytetin e Pejës, ElektroNova lindi me një mision të qartë: të bëhet lider në ofrimin e zgjidhjeve të sigurisë dhe instalimeve elektrike në tërë territorin e Kosovës. Vizioni ynë është të fuqizojmë sigurinë tuaj përmes teknologjisë më të avancuar, duke krijuar mjedise më të sigurta për familjet dhe bizneset. Ne besojmë se çdo shtëpi meriton mbrojtje maksimale dhe çdo biznes meriton stabilitet operativ.","integrity_title":"Integriteti","integrity_p":"Ne veprojmë me ndershmëri absolute në çdo konsultim. Nëse një sistem nuk ju nevojitet, ne nuk do t\'ju rekomandojmë atë. Transparenca është shtylla jonë kryesore.","innovation_title":"Inovacioni","innovation_p":"Bota e sigurisë ndryshon çdo ditë. Ekipi ynë monitoron trendet globale për të sjellë teknologjitë më të fundit AI direkt në shtëpinë apo biznesin tuaj.","standards_title":"Standardet Profesionale","standards_p1":"Në ElektroNova, ne nuk bëjmë kompromis me cilësinë. Çdo projekt, qoftë një instalim i thjeshtë kamere apo një sistem kompleks elektrik industrial, trajtohet me profesionalizëm maksimal. Ne besojmë që siguria fillon nga detajet, andaj përdorim vetëm brendet më të besueshme botërore si Dahua, Hikvision dhe Ajax.","standards_p2":"Procesi ynë i punës është i certifikuar dhe ndjek udhëzimet më të rrepta teknike. Ne sigurohemi që çdo kabull të jetë i mbrojtur, çdo lidhje të jetë e izoluar dhe çdo pajisje të jetë e konfiguruar për performancë maksimale dhe rezistencë ndaj kushteve atmosferike.","quote_text":"\\"Siguria juaj nuk është thjesht punë për ne, është përgjegjësi. Ne kombinojmë pasionin për teknologjinë me përkushtimin ndaj klientit për të ofruar paqe dhe qetësi shpirtërore.\\"","geography_title":"Rrënjët në Pejë, Mbulim në Kosovë","geography_p1":"Megjithëse seli jonë kryesore ndodhet në Pejë (Haxhi Muzlija nr 48), ElektroNova operon me një rrjet mobil që mbulon çdo qoshe të Kosovës. Kemi arritur të ndërtojmë një reputacion të pathyeshëm nga Prishtina në Prizren, dhe nga Mitrovica në Gjilan.","geography_p2":"Lidhja jonë me komunitetin është e fortë. Ne kuptojmë nevojat specifike të banorëve të zonës së Rrafshit të Dukagjinit dhe më gjerë. Kjo na lejon të ofrojmë zgjidhje që janë jo vetëm teknike, por edhe praktike për jetën e përditshme të bashkëqytetarëve tanë.","stat_founded":"Themeluar","stat_coverage":"Qytete Mbulim","stat_support":"Asistencë","stat_reliability":"Besueshmëri"},"Contact":{"title_main":"Na","title_highlight":"Kontaktoni","description":"Keni një pyetje apo kërkoni një ofertë? Ekipi ynë është i gatshëm t\'ju ndihmojë për çdo nevojë të sigurisë dhe energjisë.","office_title":"Zyra jonë","google_maps":"Hape në Google Maps →","contact_details":"Detajet e Kontaktit","hours_title":"Orari i Punës","send_message":"Dërgoni një","message_highlight":"Mesazh","map_label":"Harta e Lokacionit — ElektroNova Pejë"},"FAQPage":{"title_main":"Pyetjet e","title_highlight":"Shpeshta","description":"Gjithçka që ju duhet të dini për shërbimet tona të sigurisë.","q1":"A mund të shoh pamjet e kamerave nga jashtë vendit?","a1":"Po, absolutisht. Të gjitha sistemet tona CCTV janë të lidhura me Cloud. Përmes aplikacionit në telefonin tuaj, ju mund të monitoroni pronën tuaj në kohë reale nga çdo vend i botës që ka qasje në internet. Ky shërbim është falas dhe i enkriptuar për sigurinë tuaj.","q2":"Sa kushton një sistem i plotë i kamerave për një shtëpi?","a2":"Çmimi varet nga numri i kamerave, rezolucioni (2MP, 4MP apo 4K) dhe sasia e memorisë për regjistrim. Ne ofrojmë konsulta falas ku vijmë në lokacionin tuaj dhe ju japim një ofertë të detajuar që i përshtatet buxhetit dhe nevojave tuaja specifike.","q3":"A duhet të shpohen muret për të instaluar alarmin?","a3":"Nëse zgjidhni sistemet tona Wireless (si brendi Ajax), nuk ka nevojë për asnjë shpim apo kabllim të dukshëm. Senzorët vendosen me mbajtëse magnetike ose vida minimale. Kjo i bën ato ideale për shtëpitë e sapo renovuara apo apartamentet.","q4":"Çka ndodh nëse bie rryma?","a4":"Sistemet tona janë të pajisura me bateri rezervë (UPS). Në rast të ndaljes së rrymës, alarmi dhe kamerat vazhdojnë të punojnë deri në 8-12 orë (varësisht nga konfigurimi). Ju do të njoftoheni në telefon menjëherë sapo sistemi të kalojë në bateri.","q5":"A ofroni mirëmbajtje pas instalimit?","a5":"Po, ElektroNova ofron kontrata të rregullta mirëmbajtjeje për bizneset dhe asistencë sipas kërkesës për klientët privatë. Ne kujdesemi që lentet e kamerave të jenë të pastra, Hard Disku të jetë në gjendje të mirë dhe sistemi i alarmit të testohet periodikisht.","q6":"A mbuloni qytetin tim me shërbime?","a6":"Ne mbulojmë tërë territorin e Kosovës. Megjithëse seli jonë është në Pejë, ekipet tona teknike lëvizin çdo ditë në Prishtinë, Prizren, Mitrovicë, Gjakovë, Gjilan, Ferizaj dhe në të gjitha komunat e tjera.","not_found_title":"Nuk e gjetët përgjigjen?","not_found_desc":"Ekipi ynë është i gatshëm t\'ju ndihmojë me çdo paqartësi tjetër.","contact_us":"Na Kontaktoni","whatsapp":"Na shkruani në WhatsApp"},"Locations":{"kosovo":"Kosovë","services_in":"Shërbimet tona në","realizations_in":"Realizimet tona në","why_elektronova_in":"Pse ElektroNova në","local_presence_desc":"Duke qenë prezent lokalisht, ne kuptojmë sfidat specifike të sigurisë që kanë qytetarët dhe bizneset në {city}. Ne ofrojmë një kombinim të teknologjisë globale dhe kujdesit lokal.","service_coverage":"Mbulimi i Shërbimit","coverage_desc":"ElektroNova mbulon çdo lagje dhe zonë rurale në {city}. Pavarësisht nëse jeni në qendër të qytetit apo në zonat periferike, ekipi ynë mobil vjen te ju për instalim dhe asistencë teknike.","consultation_in":"Konsultë në","consultation_desc":"Dëshironi të siguroni pronën tuaj në {city}? Plotësoni formën për një vlerësim falas në terren.","local_line":"Linja Lokale:","fast_service_kosovo":"Shërbim i shpejtë për tërë Kosovën"},"Cities":{"prishtine":"Prishtinë","prizren":"Prizren","peje":"Pejë","ferizaj":"Ferizaj","gjilan":"Gjilan","mitrovice":"Mitrovicë","gjakove":"Gjakovë","fushe-kosove":"Fushë Kosovë","podujeve":"Podujevë","vushtrri":"Vushtrri","suhareke":"Suharekë","rahovec":"Rahovec","lipjan":"Lipjan","kamenice":"Kamenicë","decan":"Deçan","istog":"Istog","malisheve":"Malishevë","skenderaj":"Skenderaj","gracanice":"Graçanicë","kline":"Klinë","shtime":"Shtime","obiliq":"Obiliq","drenas":"Drenas","junik":"Junik","hani-i-elezit":"Hani i Elezit"},"Compliance":{"privacy_title":"Politika e Privatësisë","cookie_title":"Politika e Kukive","terms_title":"Kushtet e Përdorimit","last_updated":"Përditësuar së fundmi: 17 Mars 2026","cookie_banner_title":"Ne vlerësojmë privatësinë tuaj","cookie_banner_desc":"Ne përdorim kuki për të përmirësuar përvojën tuaj të lundrimit, për të shfaqur reklama ose përmbajtje të personalizuara dhe për të analizuar trafikun tonë. Duke klikuar \\"Prano të Gjitha\\", ju jepni pëlqimin për përdorimin e kukive tona.","accept_all":"Prano të Gjitha","reject_all":"Refuzo të Gjitha","customize":"Personalizo","save_preferences":"Ruaj Preferencat","manage_cookies":"Menaxho Kukit","form_notice":"Duke dërguar këtë formë, ju pajtoheni me përpunimin e të dhënave tuaja nga ElektroNova me qëllim të përgjigjes ndaj kërkesës suaj. Për më shumë, shihni [privacy_policy].","form_checkbox":"Pajtohem me politikën e privatësisë","categories":{"necessary":"Të Domosdoshme","necessary_desc":"Këto kuki janë thelbësore për funksionimin e faqes dhe nuk mund të fiken.","analytics":"Analitike","analytics_desc":"Na ndihmojnë të kuptojmë se si vizitorët ndërveprojnë me faqen.","marketing":"Marketing","marketing_desc":"Përdoren për të gjurmuar vizitorët ndërmjet faqeve për reklamim të personalizuar."},"privacy_sections":{"s1_title":"1. Kontrolluesi i të Dhënave","s1_content":"ElektroNova, me seli në Rr. Haxhi Muzlija nr 48, 30000 Pejë, Kosovë, është kontrolluesi i të dhënave tuaja personale. Mund të na kontaktoni në endritsmajlib@gmail.com për çdo pyetje.","s2_title":"2. Të Dhënat që Mbledhim","s2_content":"Ne mbledhim të dhëna përmes: 1) Formave të kontaktit (Emri, Email, Telefon, Qyteti), 2) Analitikës (Adresa IP, lloji i shfletuesit), 3) Kukive (Identifikuesit e gjurmimit).","s3_title":"3. Baza Ligjore","s3_content":"Ne përpunojmë të dhënat tuaja bazuar në pëlqimin tuaj të shprehur (Neni 6 i Ligjit Nr. 06/L-082) dhe për nevojën e përmbushjes së një kontrate ose kërkesave parakontraktuale.","s4_title":"4. Qëllimi i Përpunimit","s4_content":"Të dhënat tuaja përdoren vetëm për t\'iu përgjigjur kërkesave tuaja për shërbim, për të përmirësuar performancën e faqes sonë dhe për të garantuar sigurinë e saj.","s5_title":"5. Periudha e Ruajtjes","s5_content":"Ne i mbajmë të dhënat tuaja personale vetëm për aq kohë sa është e nevojshme për qëllimet për të cilat janë mbledhur ose për të përmbushur kërkesat ligjore.","s6_title":"6. Të Drejtat tuaja","s6_content":"Sipas Ligjit të Kosovës Nr. 06/L-082, ju keni të drejtë të keni qasje, të korrigjoni ose të fshini të dhënat tuaja, dhe të drejtën për të kundërshtuar përpunimin. Kontaktoni zyrën tonë për këto të drejta.","s7_title":"7. Palët e Treta","s7_content":"Ne nuk i shesim të dhënat tuaja. Ne përdorim përpunues të besuar për analitikë (Google) dhe harta, të cilët janë në përputhje me standardet e mbrojtjes së të dhënave.","s8_title":"8. Siguria","s8_content":"Ne zbatojmë masa të larta teknike dhe organizative për të parandaluar qasjen e paautorizuar ose shkeljet e të dhënave."},"terms_sections":{"t1_title":"1. Pranimi i Kushteve","t1_content":"Duke hyrë dhe përdorur faqen e internetit të ElektroNova, ju pranoni të jeni të lidhur me këto Kushte të Përdorimit dhe të gjitha ligjet dhe rregulloret e zbatueshme në Kosovë.","t2_title":"2. Pronësia Intelektuale","t2_content":"Materialet në këtë faqe (tekstet, imazhet, logot) janë pronë intelektuale e ElektroNova. Ju nuk lejohet të kopjoni ose përdorni ato për qëllime komerciale pa pëlqimin tonë paraprak me shkrim.","t3_title":"3. Deklarata e Mospërgjegjësisë","t3_content":"ElektroNova bën çdo përpjekje për të siguruar saktësinë e informacionit, por nuk garanton që materialet janë gjithmonë të sakta, të plota ose aktuale.","t4_title":"4. Kontrata Formale","t4_content":"Përshkrimet e shërbimeve janë për qëllime informative. Një kontratë formale do të lidhet për çdo projekt apo instalim specifik."}}}'))},39320,e=>{e.v(JSON.parse('{"Index":{"title":"ElektroNova - Powering Your Security","description":"Premium security solutions and electrical installations across all of Kosovo.","hero_badge":"ElektroNova - Powering Your Security","hero_h1":"Powering Your <gradient>Security</gradient> with Technology","hero_p":"ElektroNova offers premium solutions for monitoring, alarms, and electrical installations. Your security is our top priority across Kosovo.","services_title":"Our <highlight>Main</highlight> Services","services_highlight":"Main","services_p":"We offer a wide range of technological services to secure your environment.","view_all_services":"View all services","testimonials_title":"Customer <highlight>Trust</highlight>","testimonials_p":"What those who have trusted their security in our hands have to say.","mission_badge":"Our Mission & History","mission_title":"Over a Decade of Experience in <highlight>Security Technology</highlight>","mission_p1":"ElektroNova is not just a name in the security industry; it is a promise of protection and professionalism. Founded in Peja, our company was born from the need to bring European standards to the field of video surveillance and electrical installations throughout Kosovo.","mission_p2":"Over the years, we have evolved alongside technology. From the analog cameras of 10 years ago, today we are leaders in installing systems with Artificial Intelligence, face recognition, and smart home systems fully managed from your mobile.","mission_p3":"Today, we cover every city in Kosovo, offering fast services and 24/7 maintenance. We believe that technology should serve people, so each of our projects is specifically designed to meet the unique needs of our clients.","recent_work_title":"Our <highlight>Recent</highlight> Work","recent_work_p":"Direct views from our real installations across Kosovo.","view_full_gallery":"View Full Gallery","why_title":"Why choose <highlight>ElektroNova</highlight>?","why_1_title":"Professional Installation & Hidden Cabling","why_1_p":"Our trained technicians ensure every installation is performed to the highest security standards, hiding and protecting every cable.","why_2_title":"24/7 Local Support across Kosovo","why_2_p":"Based in Peja, we cover all cities in Kosovo with fast intervention, maintenance, and technical assistance.","why_3_title":"Latest Technology from World Brands","why_3_p":"We only work with world-leading brands like Dahua, Hikvision, and Ajax to guarantee longevity.","consultation_title":"Request a <highlight>Free</highlight> Consultation","faq_title":"Frequently Asked <highlight>Questions</highlight>","faq_p":"What our clients want to know before installing security systems.","faq_1_q":"Can I see the cameras from my phone wherever I am?","faq_1_a":"Yes, completely. Our systems connect to the internet and allow you to see live footage for free through official Android and iOS applications.","faq_2_q":"How long does a full installation take?","faq_2_a":"For an average home with 4 to 8 cameras, the installation is usually completed within one business day, including cabling and app configuration.","faq_3_q":"What happens if there\'s a power or internet outage?","faq_3_a":"Our systems can be equipped with backup batteries (UPS) that keep the cameras powered. If the internet goes down, recording continues on the local Hard Drive.","faq_4_q":"Do you offer a warranty for the devices and work?","faq_4_a":"Yes, ElektroNova offers a full warranty for all official brand devices (1-2 years) as well as a warranty for the correctness of the technical installation.","faq_5_q":"Is the alarm system difficult to use?","faq_5_a":"No, our modern systems are operated with a code or remote, and notifications come to your mobile in English, making it very simple for everyone.","faq_6_q":"Do you cover the entire territory of Kosovo?","faq_6_a":"Yes, our mobile team comes to every city and village in Kosovo for quote calculation, installation, and system maintenance.","brands_p":"We work with the best global brands"},"Navigation":{"home":"Home","about":"About Us","services":"Services","portfolio":"Portfolio","brands":"Brands","blog":"Blog","faq":"FAQ","contact":"Contact","footer_desc":"Premium solutions for security and electrical installations. Powering your security with the latest technology.","quick_links":"Quick Links","contact_us":"Contact Us","working_hours":"Working Hours","mon_fri":"Monday - Friday","sat_sun":"Saturday - Sunday","closed":"Closed","rights":"All rights reserved.","privacy_policy":"Privacy Policy","terms_of_service":"Terms of Service","locations":"Locations"},"Common":{"whatsapp":"Contact us on WhatsApp","call":"Call now","quote":"Get a quote","send":"Send","name":"Full Name","email":"Email Address","phone":"Phone Number","message":"Your message","sending":"Sending...","success_title":"Thank you!","success_message":"Your message has been sent successfully. Our team will contact you shortly.","error_message":"Something went wrong. Please try again or contact us via WhatsApp.","send_another":"Send another message"},"Blog":{"title":"ElektroNova <highlight>Blog</highlight>","subtitle":"Professional tips, product comparisons, and the latest news from the world of security technology.","meta_description":"Read our latest articles about security, CCTV technology, and electrical installations for free.","back_to_blog":"Return to all articles","security_expert":"Security Expert","questions_title":"Have questions about this topic?","share":"Share","related_services":"Related Services"},"Services":{"title_main":"Our","title_highlight":"Professional","title_suffix":"Services","description":"ElektroNova offers complete solutions for security and electrical needs. From design to installation and maintenance.","cat_cctv":"Monitoring Systems (CCTV)","cat_security":"Alarms and Security","cat_electrical":"Electrical Installations & Networks","service_description":"Professional solution tailored to your specific needs, guaranteeing maximum quality and security.","cta_title":"Not sure what you need?","cta_desc":"Contact us today for a free consultation and environment assessment by our experts.","call_expert":"Call the Expert","whatsapp":"WhatsApp","related_articles":"Related Articles","back_to_services":"Back to all services","service_description_title":"Service Description","main_benefits":"Main Benefits","tech_used":"Technology Used","where_applies":"Where does it apply?","install_process":"Installation Process","service_faq":"Service Questions","get_quote":"Get a Quote","quote_desc":"Interested in this service? Fill out the form below and our team will contact you within 24 hours.","need_help":"Need Help?","free_cons_desc":"Call us anytime for a free consultation."},"Portfolio":{"title_main":"Portfolio of","title_highlight":"Realizations","description":"Views from our real field installations. Every photo shows our commitment to quality and professionalism.","cta_title":"Ready to secure your property?","cta_desc":"We come anywhere in Kosovo for your project evaluation free of charge.","request_quote":"Request a Quote","call_phone":"Call on Phone"},"About":{"title_main":"About","title_highlight":"ElektroNova","vision_title":"Our Vision","vision_p":"Founded on January 8, 2025, in the city of Peja, ElektroNova was born with a clear mission: to become a leader in providing security solutions and electrical installations throughout the territory of Kosovo. Our vision is to empower your security through the most advanced technology, creating safer environments for families and businesses. We believe that every home deserves maximum protection and every business deserves operational stability.","integrity_title":"Integrity","integrity_p":"We act with absolute honesty in every consultation. If you don\'t need a system, we won\'t recommend it to you. Transparency is our main pillar.","innovation_title":"Innovation","innovation_p":"The world of security changes every day. Our team monitors global trends to bring the latest AI technologies directly to your home or business.","standards_title":"Professional Standards","standards_p1":"At ElektroNova, we do not compromise on quality. Every project, whether a simple camera installation or a complex industrial electrical system, is handled with maximum professionalism. We believe that security starts from the details, so we only use the most reliable world brands like Dahua, Hikvision, and Ajax.","standards_p2":"Our work process is certified and follows the strictest technical guidelines. We ensure that every cable is protected, every connection is insulated, and every device is configured for maximum performance and resistance to weather conditions.","quote_text":"\\"Your security is not just a job for us, it\'s a responsibility. We combine a passion for technology with customer commitment to offer peace and spiritual tranquility.\\"","geography_title":"Roots in Peja, Coverage in Kosovo","geography_p1":"Although our main headquarters is located in Peja (Haxhi Muzlija nr 48), ElektroNova operates with a mobile network that covers every corner of Kosovo. We have managed to build an unbreakable reputation from Prishtina to Prizren, and from Mitrovica to Gjilan.","geography_p2":"Our connection with the community is strong. We understand the specific needs of the residents of the Dukagjin Plain and beyond. This allows us to offer solutions that are not only technical but also practical for the daily life of our fellow citizens.","stat_founded":"Founded","stat_coverage":"Cities Covered","stat_support":"Assistance","stat_reliability":"Reliability"},"Contact":{"title_main":"Contact","title_highlight":"Us","description":"Have a question or looking for a quote? Our team is ready to help you with every security and energy need.","office_title":"Our Office","google_maps":"Open in Google Maps →","contact_details":"Contact Details","hours_title":"Working Hours","send_message":"Send a","message_highlight":"Message","map_label":"Location Map — ElektroNova Peja"},"FAQPage":{"title_main":"Frequently Asked","title_highlight":"Questions","description":"Everything you need to know about our security services.","q1":"Can I see the camera footage from abroad?","a1":"Yes, absolutely. All our CCTV systems are Cloud-connected. Through the app on your phone, you can monitor your property in real-time from anywhere in the world with internet access. This service is free and encrypted for your security.","q2":"How much does a full camera system cost for a home?","a2":"The price depends on the number of cameras, resolution (2MP, 4MP or 4K), and the amount of storage for recording. We offer free consultations where we come to your location and give you a detailed quote that fits your budget and specific needs.","q3":"Do walls need to be drilled to install the alarm?","a3":"If you choose our Wireless systems (like the Ajax brand), there is no need for any visible drilling or cabling. Sensors are placed with magnetic mounts or minimal screws. This makes them ideal for newly renovated homes or apartments.","q4":"What happens if the power goes out?","a4":"Our systems are equipped with backup batteries (UPS). In case of power failure, the alarm and cameras continue to work for up to 8-12 hours (depending on configuration). You will be notified on your phone as soon as the system switches to battery.","q5":"Do you offer maintenance after installation?","a5":"Yes, ElektroNova offers regular maintenance contracts for businesses and on-demand assistance for private clients. We make sure camera lenses are clean, the Hard Drive is in good condition, and the alarm system is periodically tested.","q6":"Do you cover my city with services?","a6":"We cover the entire territory of Kosovo. Although our headquarters is in Peja, our technical teams move daily to Prishtina, Prizren, Mitrovica, Gjakova, Gjilan, Ferizaj and all other municipalities.","not_found_title":"Didn\'t find the answer?","not_found_desc":"Our team is ready to help you with any other uncertainties.","contact_us":"Contact Us","whatsapp":"Write to us on WhatsApp"},"Locations":{"kosovo":"Kosovo","services_in":"Our services in","realizations_in":"Our realizations in","why_elektronova_in":"Why ElektroNova in","local_presence_desc":"Being locally present, we understand the specific security challenges that citizens and businesses have in {city}. We offer a combination of global technology and local care.","service_coverage":"Service Coverage","coverage_desc":"ElektroNova covers every neighborhood and rural area in {city}. Whether you are in the city center or the outskirts, our mobile team comes to you for installation and technical assistance.","consultation_in":"Consultation in","consultation_desc":"Want to secure your property in {city}? Fill out the form for a free on-site assessment.","local_line":"Local Line:","fast_service_kosovo":"Fast service for all of Kosovo"},"Cities":{"prishtine":"Prishtina","prizren":"Prizren","peje":"Peja","ferizaj":"Ferizaj","gjilan":"Gjilan","mitrovice":"Mitrovica","gjakove":"Gjakova","fushe-kosove":"Fushe Kosovo","podujeve":"Podujeva","vushtrri":"Vushtrri","suhareke":"Suhareka","rahovec":"Rahovec","lipjan":"Lipjan","kamenice":"Kamenica","decan":"Deçan","istog":"Istog","malisheve":"Malisheva","skenderaj":"Skenderaj","gracanice":"Gracanica","kline":"Klina","shtime":"Shtime","obiliq":"Obiliq","drenas":"Drenas","junik":"Junik","hani-i-elezit":"Hani i Elezit"},"Compliance":{"privacy_title":"Privacy Policy","cookie_title":"Cookie Policy","terms_title":"Terms of Service","last_updated":"Last updated: March 17, 2026","cookie_banner_title":"We value your privacy","cookie_banner_desc":"We use cookies to enhance your browsing experience, serve personalized ads or content, and analyze our traffic. By clicking \\"Accept All\\", you consent to our use of cookies.","accept_all":"Accept All","reject_all":"Reject All","customize":"Customize","save_preferences":"Save Preferences","manage_cookies":"Manage Cookies","form_notice":"By submitting this form, you agree to the processing of your data by ElektroNova for the purpose of responding to your request. For more information, see our [privacy_policy].","form_checkbox":"I agree to the privacy policy","categories":{"necessary":"Strictly Necessary","necessary_desc":"These cookies are essential for the website to function and cannot be switched off.","analytics":"Analytics","analytics_desc":"Help us understand how visitors interact with the website.","marketing":"Marketing","marketing_desc":"Used to track visitors across websites to enable personalized advertising."},"privacy_sections":{"s1_title":"1. Data Controller","s1_content":"ElektroNova, located at Rr. Haxhi Muzlija nr 48, 30000 Peja, Kosovo, is the controller for your personal data. You can contact us at endritsmajlib@gmail.com for any privacy concerns.","s2_title":"2. Data We Collect","s2_content":"We collect data through: 1) Contact forms (Name, Email, Phone, City), 2) Analytics (IP address, Browser type), 3) Cookies (Tracking identifiers).","s3_title":"3. Legal Basis","s3_content":"We process your data based on your explicit consent (Art. 6 of Law No. 06/L-082) and for the necessity of fulfilling a contract or pre-contractual requests.","s4_title":"4. Purpose of Processing","s4_content":"Your data is used solely to respond to your service requests, improve our website performance, and ensure site security.","s5_title":"5. Data Retention","s5_content":"We keep your personal data only as long as necessary for the purposes for which it was collected or to comply with legal requirements.","s6_title":"6. Your Rights","s6_content":"Under Kosovo Law No. 06/L-082, you have the right to access, rectify, or erase your data, and the right to object to processing. Contact our office to exercise these rights.","s7_title":"7. Third Parties","s7_content":"We do not sell your data. We use trusted processors for analytics (Google) and maps, who are compliant with data protection standards.","s8_title":"8. Security","s8_content":"We implement high-level technical and organizational measures to prevent unauthorized access or data breaches."},"terms_sections":{"t1_title":"1. Acceptance of Terms","t1_content":"By accessing and using the ElektroNova website, you agree to be bound by these Terms of Service and all applicable laws and regulations in Kosovo.","t2_title":"2. Intellectual Property","t2_content":"The materials on this site (text, images, logos) are the intellectual property of ElektroNova. You may not copy or use them for commercial purposes without our prior written consent.","t3_title":"3. Disclaimer","t3_content":"ElektroNova makes every effort to ensure the accuracy of information, but does not guarantee that materials are always accurate, complete, or current.","t4_title":"4. Formal Contract","t4_content":"Service descriptions are for information purposes. A formal contract will be signed for every specific project or installation."}}}'))}]);

